const body = $input.item.json.body;
const skill = body.skill;
const inputs = body.inputs || {};

const skills = {

  'roadmap-builder': {
    system: `You are an expert product strategist. Create structured, actionable product roadmaps. Output in clean markdown with these sections: ## Executive Summary, ## Goals & Success Metrics, ## Roadmap by Quarter (or relevant timeframes), ## Key Risks & Dependencies, ## Open Questions. Be specific — include initiative names, not vague themes.`,
    user: `Build a product roadmap with the following context:

Goals: ${inputs.goals || ''}
Constraints: ${inputs.constraints || ''}
Priorities: ${inputs.priorities || ''}
Timeframe: ${inputs.timeframe || '12 months'}
Team size: ${inputs.team_size || 'not specified'}

Output a complete, structured roadmap ready to share with stakeholders.`
  },

  'go-to-market': {
    system: `You are an expert go-to-market strategist. Create comprehensive GTM plans with channels, messaging, timeline, and success metrics. Output in clean markdown. Be specific about channel tactics, not generic advice.`,
    user: `Create a go-to-market strategy:

Product: ${inputs.product || ''}
Target Market: ${inputs.target_market || ''}
Launch Date: ${inputs.launch_date || ''}
Budget: ${inputs.budget || 'not specified'}
Key Differentiators: ${inputs.differentiators || ''}
Current stage: ${inputs.stage || 'pre-launch'}

Output: positioning, channels with specific tactics, messaging framework, 90-day timeline, and success metrics.`
  },

  'bcg-matrix': {
    system: `You are an expert in portfolio strategy. Analyze products using the BCG Growth-Share Matrix. For each product give: quadrant placement with reasoning, strategic recommendation (invest/milk/divest/nurture), specific actions, and resource implications. End with portfolio-level strategic recommendations.`,
    user: `Analyze this product portfolio using the BCG Matrix:

${inputs.products ? JSON.stringify(inputs.products, null, 2) : inputs.context || ''}

For each product include: market growth rate assessment, relative market share assessment, quadrant placement, and specific strategic actions. Close with overall portfolio health and rebalancing recommendations.`
  },

  'swot-analysis': {
    system: `You are an expert strategic analyst. Create comprehensive SWOT analyses that go beyond listing — connect the quadrants and recommend concrete SO (use strengths to capture opportunities), WO (fix weaknesses to capture opportunities), ST (use strengths to counter threats), and WT (minimize weaknesses, avoid threats) strategies. Output in clean markdown.`,
    user: `Create a SWOT analysis:

Company/Product: ${inputs.company || inputs.product || ''}
Industry: ${inputs.industry || ''}
Context: ${inputs.context || ''}
Key question to answer: ${inputs.question || 'What should our strategic priorities be?'}

Output: full four-quadrant SWOT, cross-quadrant strategic implications, and top 3 recommended actions with rationale.`
  },

  'pricing-strategy': {
    system: `You are an expert in SaaS and product pricing strategy. Analyze pricing with competitive positioning, packaging options, and revenue modeling. Give specific recommendations with numbers, not ranges. Output in clean markdown.`,
    user: `Analyze pricing strategy:

Product: ${inputs.product || ''}
Current Pricing: ${inputs.current_pricing || 'not set'}
Competitors and their pricing: ${inputs.competitors || ''}
Target Segment: ${inputs.target_segment || ''}
Business Model: ${inputs.business_model || 'SaaS'}
Annual Revenue Target: ${inputs.revenue_target || 'not specified'}

Output: pricing model recommendation, packaging tiers (name, price, what's included), competitive positioning, and a simple revenue projection at each tier.`
  },

  'market-sizing': {
    system: `You are an expert in market research and sizing. Calculate TAM/SAM/SOM using both top-down and bottom-up approaches. Show your math step by step. State every assumption explicitly. Flag confidence level (high/medium/low) for each number.`,
    user: `Calculate market size:

Market: ${inputs.market || ''}
Geography: ${inputs.geography || 'Global'}
Target customer: ${inputs.target_customer || ''}
Additional context: ${inputs.context || ''}

Output: TAM, SAM, SOM for both top-down and bottom-up approaches with full calculations, explicit assumptions, confidence levels, and a recommended number to use for planning.`
  },

  'competitive-landscape': {
    system: `You are an expert in competitive analysis. Map competitive landscapes clearly. For each competitor: what they do, who they target, how they position, their strengths and weaknesses, and their likely strategic moves. End with white space opportunities and strategic recommendations. Use text-based tables and positioning maps where helpful.`,
    user: `Map the competitive landscape:

Our Product: ${inputs.product || ''}
Our target customer: ${inputs.target_customer || ''}
Competitors to analyze: ${inputs.competitors || ''}
Key dimensions to evaluate: ${inputs.dimensions || 'price, features, ease of use, market focus'}
Market context: ${inputs.market || ''}

Output: competitor profiles table, text-based positioning matrix, white space opportunities, and top 3 strategic recommendations.`
  }

};

const skill_config = skills[skill];
if (!skill_config) {
  throw new Error(`Unknown skill: "${skill}". Valid options: ${Object.keys(skills).join(', ')}`);
}

return {
  skill: skill,
  system_prompt: skill_config.system,
  user_message: skill_config.user
};

const raw = $input.item.json;
const content = raw.content && raw.content[0] ? raw.content[0].text : '';
const skill = $('Build Prompt').item.json.skill;

return {
  skill: skill,
  content: content,
  word_count: content.split(/\s+/).filter(w => w).length,
  generated_at: new Date().toISOString()
};
